#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to search for a value in the BST
bool searchInBST(Node* root, int x) {
    if (root == NULL) {
        return false;
    }
    if (root->val == x) {
        return true;
    }
    if (root->val < x) {
        return searchInBST(root->right, x);
    } else {
        return searchInBST(root->left, x);
    }
}

int main() {
    int N, X;
    scanf("%d %d", &N, &X);
    Node* root = NULL;
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        // Create nodes and assign them to the tree
        if (root == NULL) {
            root = createNode(pi);
        }
        Node* newNode = createNode(ci);
        Node* currentNode = root;
        while (currentNode != NULL) {
            if (currentNode->val == pi) {
                if (Ri == 'L') {
                    currentNode->left = newNode;
                } else {
                    currentNode->right = newNode;
                }
                break;
            }
            if (currentNode->val < pi) {
                if (currentNode->right == NULL) {
                    currentNode->right = createNode(pi);
                }
                currentNode = currentNode->right;
            } else {
                if (currentNode->left == NULL) {
                    currentNode->left = createNode(pi);
                }
                currentNode = currentNode->left;
            }
        }
    }
    bool found = searchInBST(root, X);
    if (found) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

